function createPluralRule(locale, mapping) {
  return (choice, choicesLength) => {
    const name = new Intl.PluralRules(locale).select(choice);
    const plural = mapping[name] || 0;
    if (plural > choicesLength - 1) {
      return choicesLength - 1;
    }
    return plural;
  };
}
